import{_ as r,C as a,o as l,c as d,j as t,a as c,E as o,a4 as n}from"./chunks/framework.BdVCF3pj.js";const w=JSON.parse('{"title":"Pagination Strategies","description":"","frontmatter":{"aside":false,"pageClass":"table-anatomy-doc"},"headers":[],"relativePath":"concepts/pagination-strategies.md","filePath":"concepts/pagination-strategies.md"}'),g={name:"concepts/pagination-strategies.md"};function p(h,e,u,m,f,b){const i=a("PaginationStrategies",!0),s=a("LabPaginationSandbox");return l(),d("div",null,[e[0]||(e[0]=t("h1",{id:"pagination-strategies",tabindex:"-1"},[c("Pagination Strategies "),t("a",{class:"header-anchor",href:"#pagination-strategies","aria-label":'Permalink to "Pagination Strategies"'},"​")],-1)),e[1]||(e[1]=t("p",null,"Pagination is the part of table testing that most often depends on your app. Smart Table does not guess how your UI moves; you describe the movement with a pagination strategy.",-1)),e[2]||(e[2]=t("p",null,"This page shows common pagination shapes and the strategy primitive that usually fits.",-1)),o(i),e[3]||(e[3]=n('<h2 id="what-to-notice" tabindex="-1">What To Notice <a class="header-anchor" href="#what-to-notice" aria-label="Permalink to &quot;What To Notice&quot;">​</a></h2><ul><li><code>goNext</code> and <code>goPrevious</code> are enough for simple one-page-at-a-time searches.</li><li><code>goToFirst</code> is useful when a scan or reset should start from page one.</li><li><code>goToLast</code> enables optimal path planning (wrap-around) when navigating to distant pages.</li><li><code>goToPage</code> fits numbered pagination or page inputs.</li><li><code>numberOfPages</code> allows Smart Table to calculate the most efficient path between distant pages (e.g., jumping to the last page first).</li><li>Infinite scroll and load-more UIs still use the pagination strategy slot; the strategy just scrolls or loads instead of clicking a numbered pagination component.</li></ul><p>Each primitive should return <code>true</code> when movement happened and <code>false</code> when there is nowhere else to go. For exact signatures, see <a href="/playwright-smart-table/pr-preview/pr-156/api/strategies.html#pagination-strategies">Pagination Strategies</a>.</p><hr><h2 id="try-it-—-pagination-config-builder" tabindex="-1">Try It — Pagination Config Builder <a class="header-anchor" href="#try-it-—-pagination-config-builder" aria-label="Permalink to &quot;Try It — Pagination Config Builder&quot;">​</a></h2><p>The sandbox below lets you explore how different pagination setups translate directly into library config. Switch between pagination types, toggle optional selectors on and off, and watch the generated config update live. Use the plan builder to pick a target page and see exactly which primitives Smart Table would call to get there — then step through or run them all at once against the mock table.</p>',6)),o(s),e[4]||(e[4]=n('<h3 id="what-to-notice-1" tabindex="-1">What to notice <a class="header-anchor" href="#what-to-notice-1" aria-label="Permalink to &quot;What to notice&quot;">​</a></h3><ul><li><strong>Toggling <code>first</code> / <code>last</code> off</strong> removes those lines from the config and changes the plan: without <code>goToLast</code>, wrap-around paths are unavailable; without <code>goToFirst</code>, backward navigation must rely on <code>previous</code> or <code>previousBulk</code> alone.</li><li><strong><code>nextBulk</code> / <code>previousBulk</code> trade fewer clicks for a coarser granularity.</strong> Enable them to see the planner skip entire decades of pages instead of stepping one at a time — but note that <code>nextBulkPages</code> must match the actual number of pages your UI advances per click.</li><li><strong><code>numberOfPages</code> unlocks wrap-around.</strong> When it is enabled and <code>last</code> is present, the planner can jump to the end and work backwards — often the shortest path to a high-numbered page.</li><li><strong>Load More and Infinite Scroll are forward-only.</strong> Once content is loaded it stays in the DOM; the library only needs to advance, never retreat. That is why <code>goToFirst</code> and <code>goToPrevious</code> do not appear in those configs.</li><li><strong>Every config is minimal by design.</strong> You only describe the controls that actually exist in your UI. Anything you omit is simply not used by Smart Table during a search.</li></ul>',2))])}const T=r(g,[["render",p]]);export{w as __pageData,T as default};
